```typescript
type Method = 'GET' | 'POST' | 'PUT' | 'PATCH' | 'DELETE'

let isRefreshing = false
let failedQueue: Array<{
  resolve: (token: string) => void
  reject: (error: unknown) => void
}> = []

const processQueue = (error: unknown, token: string | null = null) => {
  failedQueue.forEach((p) => (token ? p.resolve(token) : p.reject(error)))
  failedQueue = []
}

async function doFetch(method: Method, url: string, body: unknown, token: string | null): Promise<Response> {
  const headers: Record<string, string> = { 'Content-Type': 'application/json' }
  if (token) headers['Authorization'] = `Bearer ${token}`
  return fetch(url, {
    method,
    headers,
    body: body !== undefined ? JSON.stringify(body) : undefined,
  })
}

async function parseResponse<T>(res: Response): Promise<{ data: T }> {
  if (!res.ok) return Promise.reject(await res.json().catch(() => ({})))
  return { data: (await res.json()) as T }
}

async function request<T>(method: Method, url: string, body?: unknown): Promise<{ data: T }> {
  const token = localStorage.getItem('access_token')
  const res = await doFetch(method, url, body, token)

  const isAuthEndpoint = url.includes('/auth/refresh') || url.includes('/auth/login')
  if (res.status !== 401 || isAuthEndpoint) {
    return parseResponse<T>(res)
  }

  // 401 — queue behind an in-flight refresh or start one
  if (isRefreshing) {
    return new Promise<{ data: T }>((resolve, reject) => {
      failedQueue.push({
        resolve: (newToken) => resolve(doFetch(method, url, body, newToken).then((r) => parseResponse<T>(r))),
        reject,
      })
    })
  }

  isRefreshing = true

  try {
    const refreshToken = localStorage.getItem('refresh_token')
    if (!refreshToken) throw new Error('No refresh token')

    const refreshRes = await fetch('/api/v1/auth/refresh', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ refresh_token: refreshToken }),
    })

    if (!refreshRes.ok) throw new Error('Token refresh failed')

    const { access_token } = await refreshRes.json()
    localStorage.setItem('access_token', access_token)
    processQueue(null, access_token)

    return parseResponse<T>(await doFetch(method, url, body, access_token))
  } catch (err) {
    processQueue(err, null)
    localStorage.removeItem('access_token')
    localStorage.removeItem('refresh_token')
    window.location.href = '/login'
    return Promise.reject(err)
  } finally {
    isRefreshing = false
  }
}

const client = {
  get: <T>(url: string) => request<T>('GET', url),
  post: <T>(url: string, body?: unknown) => request<T>('POST', url, body),
  put: <T>(url: string, body?: unknown) => request<T>('PUT', url, body),
  patch: <T>(url: string, body?: unknown) => request<T>('PATCH', url, body),
  delete: <T>(url: string, body?: unknown) => request<T>('DELETE', url, body),
}

export default client
```

