import { describe, it, expect } from 'vitest'
import { render, screen, waitFor } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { useForm } from 'react-hook-form'
import { zodResolver } from '@hookform/resolvers/zod'
import { z } from 'zod'

const schema = z.object({
  email: z.string().email('bad email'),
  password: z.string().min(1, 'required'),
})

function SimpleForm() {
  const { register, handleSubmit, formState: { errors } } = useForm({
    resolver: zodResolver(schema),
    defaultValues: { email: '', password: '' },
  })
  return (
    <form onSubmit={handleSubmit(() => {})}>
      <input {...register('email')} data-testid="email" />
      {errors.email && <span data-testid="email-error">{errors.email.message}</span>}
      <input {...register('password')} data-testid="password" />
      {errors.password && <span data-testid="password-error">{errors.password.message}</span>}
      <button type="submit">Submit</button>
    </form>
  )
}

describe('rhf-debug', () => {
  it('shows email error when email invalid', async () => {
    const user = userEvent.setup()
    render(<SimpleForm />)

    await user.type(screen.getByTestId('email'), 'notanemail')
    await user.type(screen.getByTestId('password'), 'pw')
    await user.click(screen.getByRole('button', { name: 'Submit' }))

    await waitFor(() => {
      expect(screen.queryByTestId('email-error')?.textContent).toBeTruthy()
    }, { timeout: 3000 })
  })

  it('shows password error when password empty', async () => {
    const user = userEvent.setup()
    render(<SimpleForm />)

    await user.type(screen.getByTestId('email'), 'a@b.com')
    await user.click(screen.getByRole('button', { name: 'Submit' }))

    await waitFor(() => {
      expect(screen.queryByTestId('password-error')?.textContent).toBeTruthy()
    }, { timeout: 3000 })
  })
})

