import { describe, it, expect, vi, beforeEach } from 'vitest'
import { render, screen, waitFor } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { MemoryRouter } from 'react-router-dom'
import { LoginPage } from './pages/login'
import { useAuth } from './hooks/use-auth'

vi.mock('./hooks/use-auth')
const mockNavigate = vi.fn()
vi.mock('react-router-dom', async (i) => {
  const a = await i<typeof import('react-router-dom')>()
  return { ...a, useNavigate: () => mockNavigate }
})
const mockLogin = vi.fn()

describe('rhf-debug', () => {
  beforeEach(() => {
    vi.mocked(useAuth).mockReturnValue({ user: null, isLoading: false, login: mockLogin, logout: vi.fn() })
    mockLogin.mockReset()
    mockNavigate.mockReset()
  })

  it('logs email value and errors after submit', async () => {
    const user = userEvent.setup()
    render(<MemoryRouter><LoginPage /></MemoryRouter>)

    const emailInput = screen.getByLabelText('Email') as HTMLInputElement
    const pwInput = screen.getByLabelText('Password') as HTMLInputElement

    await user.type(emailInput, 'notanemail')
    console.log('email value after type:', emailInput.value)

    await user.type(pwInput, 'pw')
    console.log('email value after pw type:', emailInput.value)
    console.log('password value:', pwInput.value)

    await user.click(screen.getByRole('button', { name: 'Sign in' }))
    console.log('after click - login called:', mockLogin.mock.calls.length > 0)

    await new Promise(r => setTimeout(r, 500))

    const emailLabel = document.querySelector('[data-slot="form-label"][for]')
    console.log('email label data-error:', emailLabel?.getAttribute('data-error'))

    const errorMessages = document.querySelectorAll('[data-slot="form-message"]')
    console.log('error message elements:', errorMessages.length)
    errorMessages.forEach(el => console.log(' -', el.textContent))

    expect(mockLogin).not.toHaveBeenCalled()
  })
})

