import { describe, it, expect, vi, beforeEach } from 'vitest'
import { render, screen, waitFor, fireEvent } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { MemoryRouter } from 'react-router-dom'
import { LoginPage } from './pages/login'
import { useAuth } from './hooks/use-auth'

vi.mock('./hooks/use-auth')
const mockNavigate = vi.fn()
vi.mock('react-router-dom', async (i) => {
  const a = await i<typeof import('react-router-dom')>()
  return { ...a, useNavigate: () => mockNavigate }
})
const mockLogin = vi.fn()

describe('rhf-debug', () => {
  beforeEach(() => {
    vi.mocked(useAuth).mockReturnValue({ user: null, isLoading: false, login: mockLogin, logout: vi.fn() })
    mockLogin.mockReset()
    mockNavigate.mockReset()
  })

  it('fireEvent.submit — email error shows?', async () => {
    const user = userEvent.setup()
    render(<MemoryRouter><LoginPage /></MemoryRouter>)

    await user.type(screen.getByLabelText('Email'), 'notanemail')
    await user.type(screen.getByLabelText('Password'), 'pw')

    // Use fireEvent.submit directly on form
    const form = document.querySelector('form')!
    fireEvent.submit(form)

    await waitFor(() => {
      const msgs = document.querySelectorAll('[data-slot="form-message"]')
      console.log('msgs with fireEvent.submit:', msgs.length, msgs.length > 0 ? msgs[0].textContent : '')
      expect(mockLogin).not.toHaveBeenCalled()
    }, { timeout: 3000 })
  })

  it('userEvent.click — password only — works', async () => {
    const user = userEvent.setup()
    render(<MemoryRouter><LoginPage /></MemoryRouter>)
    await user.type(screen.getByLabelText('Email'), 'a@b.com')
    await user.click(screen.getByRole('button', { name: 'Sign in' }))
    await waitFor(() => expect(screen.getByText('Password is required')).toBeInTheDocument())
  })

  it('focus() on first error field = root cause?', async () => {
    const user = userEvent.setup()
    render(<MemoryRouter><LoginPage /></MemoryRouter>)

    await user.type(screen.getByLabelText('Email'), 'a@b.com')
    await user.type(screen.getByLabelText('Password'), '')  // empty
    await user.click(screen.getByRole('button', { name: 'Sign in' }))

    await waitFor(() => {
      // Now manually focus the password input to simulate _focusError
      const pw = screen.getByLabelText('Password') as HTMLInputElement
      pw.focus()
    })

    await waitFor(() => expect(screen.getByText('Password is required')).toBeInTheDocument(), { timeout: 3000 })
  })
})

