import { describe, it, expect, vi, beforeEach } from 'vitest'
import { render, screen, waitFor } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { useForm } from 'react-hook-form'
import { zodResolver } from '@hookform/resolvers/zod'
import { z } from 'zod'
import { Form, FormField, FormItem, FormLabel, FormControl, FormMessage } from './components/ui/form'
import { Input } from './components/ui/input'
import { Button } from './components/ui/button'

const schema = z.object({
  email: z.string().email('bad email'),
  password: z.string().min(1, 'password required'),
})

function ShadcnForm({ onSubmit = vi.fn() }) {
  const form = useForm({ resolver: zodResolver(schema), defaultValues: { email: '', password: '' } })
  return (
    <Form {...form}>
      <form onSubmit={form.handleSubmit(onSubmit)}>
        <FormField control={form.control} name="email" render={({ field }) => (
          <FormItem>
            <FormLabel>Email</FormLabel>
            <FormControl><Input {...field} /></FormControl>
            <FormMessage />
          </FormItem>
        )} />
        <FormField control={form.control} name="password" render={({ field }) => (
          <FormItem>
            <FormLabel>Password</FormLabel>
            <FormControl><Input {...field} /></FormControl>
            <FormMessage />
          </FormItem>
        )} />
        <Button type="submit">Submit</Button>
      </form>
    </Form>
  )
}

describe('shadcn-form-debug', () => {
  it('email error with invalid email', async () => {
    const user = userEvent.setup()
    render(<ShadcnForm />)
    await user.type(screen.getByLabelText('Email'), 'notanemail')
    await user.type(screen.getByLabelText('Password'), 'pw')
    await user.click(screen.getByRole('button', { name: 'Submit' }))
    await waitFor(() => {
      const msgs = document.querySelectorAll('[data-slot="form-message"]')
      console.log('msgs:', msgs.length, [...msgs].map(m => m.textContent).join(', '))
      expect(screen.queryByText('bad email') || screen.queryByText('password required')).toBeTruthy()
    }, { timeout: 3000 })
  })

  it('password error with valid email', async () => {
    const user = userEvent.setup()
    render(<ShadcnForm />)
    await user.type(screen.getByLabelText('Email'), 'a@b.com')
    await user.click(screen.getByRole('button', { name: 'Submit' }))
    await waitFor(() => {
      expect(screen.getByText('password required')).toBeInTheDocument()
    })
  })

  it('email error ONLY (no password typed)', async () => {
    const user = userEvent.setup()
    render(<ShadcnForm />)
    await user.type(screen.getByLabelText('Email'), 'notanemail')
    await user.click(screen.getByRole('button', { name: 'Submit' }))
    await waitFor(() => {
      const msgs = document.querySelectorAll('[data-slot="form-message"]')
      console.log('msgs with email-only typed:', msgs.length, [...msgs].map(m => m.textContent).join(', '))
    }, { timeout: 3000 })
    // just log, don't fail
    expect(true).toBe(true)
  })
})

