import { render, screen, waitFor } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { MemoryRouter } from 'react-router-dom'
import { UsersPage } from './users'
import { adminApi } from '@/api/admin'
import { toast } from 'sonner'
import type { AdminUser } from '@/types/auth'
import React from 'react'

vi.mock('@/api/admin')
vi.mock('sonner', () => ({
  toast: { error: vi.fn(), success: vi.fn() },
}))
vi.mock('@/components/app-sidebar', () => ({
  AppSidebar: ({ children }: { children: React.ReactNode }) => <>{children}</>,
}))

const mockAdminApi = vi.mocked(adminApi)
const mockToast = vi.mocked(toast)

const activeUser: AdminUser = {
  id: '1',
  email: 'user@test.com',
  role: 'user',
  email_verified: true,
  deactivated: false,
  deactivated_at: null,
  created_at: '2024-01-01T00:00:00Z',
  updated_at: '2024-01-01T00:00:00Z',
}

const deactivatedUser: AdminUser = {
  id: '2',
  email: 'banned@test.com',
  role: 'user',
  email_verified: false,
  deactivated: true,
  deactivated_at: '2024-02-01T00:00:00Z',
  created_at: '2024-01-01T00:00:00Z',
  updated_at: '2024-02-01T00:00:00Z',
}

function renderPage() {
  return render(
    <MemoryRouter>
      <UsersPage />
    </MemoryRouter>,
  )
}

describe('UsersPage', () => {
  beforeEach(() => {
    vi.clearAllMocks()
    mockAdminApi.listUsers.mockResolvedValue({ data: { users: [activeUser, deactivatedUser] } })
    mockAdminApi.deactivateUser.mockResolvedValue({
      data: { message: 'ok', user: { ...activeUser, deactivated: true, deactivated_at: '2024-03-01' } },
    })
    mockAdminApi.activateUser.mockResolvedValue({
      data: { message: 'ok', user: { ...deactivatedUser, deactivated: false, deactivated_at: null } },
    })
  })

  it('shows loading state while fetching', () => {
    mockAdminApi.listUsers.mockReturnValueOnce(new Promise(() => {}))

    renderPage()

    expect(screen.getByText('Loading...')).toBeInTheDocument()
  })

  it('renders user emails after load', async () => {
    renderPage()

    await waitFor(() => expect(screen.getByText('user@test.com')).toBeInTheDocument())
    expect(screen.getByText('banned@test.com')).toBeInTheDocument()
  })

  it('shows Deactivate button for active users', async () => {
    renderPage()

    await waitFor(() => screen.getByText('user@test.com'))
    expect(screen.getByRole('button', { name: 'Deactivate' })).toBeInTheDocument()
  })

  it('shows Activate button for deactivated users', async () => {
    renderPage()

    await waitFor(() => screen.getByText('banned@test.com'))
    expect(screen.getByRole('button', { name: 'Activate' })).toBeInTheDocument()
  })

  it('shows "No users found" for empty list', async () => {
    mockAdminApi.listUsers.mockResolvedValueOnce({ data: { users: [] } })

    renderPage()

    await waitFor(() => expect(screen.getByText('No users found')).toBeInTheDocument())
  })

  it('shows error toast when list users fails', async () => {
    mockAdminApi.listUsers.mockRejectedValueOnce(new Error('Network error'))

    renderPage()

    await waitFor(() => expect(mockToast.error).toHaveBeenCalledWith('Failed to load users'))
  })

  it('calls deactivateUser and shows success toast', async () => {
    const user = userEvent.setup()
    renderPage()

    await waitFor(() => screen.getByText('user@test.com'))
    await user.click(screen.getByRole('button', { name: 'Deactivate' }))

    await waitFor(() => expect(mockAdminApi.deactivateUser).toHaveBeenCalledWith('1'))
    expect(mockToast.success).toHaveBeenCalledWith('user@test.com deactivated')
  })

  it('calls activateUser and shows success toast', async () => {
    const user = userEvent.setup()
    renderPage()

    await waitFor(() => screen.getByText('banned@test.com'))
    await user.click(screen.getByRole('button', { name: 'Activate' }))

    await waitFor(() => expect(mockAdminApi.activateUser).toHaveBeenCalledWith('2'))
    expect(mockToast.success).toHaveBeenCalledWith('banned@test.com activated')
  })

  it('shows error toast when deactivate fails with API error', async () => {
    mockAdminApi.deactivateUser.mockRejectedValueOnce({ error: 'Cannot deactivate admin' })
    const user = userEvent.setup()
    renderPage()

    await waitFor(() => screen.getByText('user@test.com'))
    await user.click(screen.getByRole('button', { name: 'Deactivate' }))

    await waitFor(() =>
      expect(mockToast.error).toHaveBeenCalledWith('Cannot deactivate admin'),
    )
  })

  it('shows generic error toast when deactivate fails without message', async () => {
    mockAdminApi.deactivateUser.mockRejectedValueOnce(new Error('Network error'))
    const user = userEvent.setup()
    renderPage()

    await waitFor(() => screen.getByText('user@test.com'))
    await user.click(screen.getByRole('button', { name: 'Deactivate' }))

    await waitFor(() =>
      expect(mockToast.error).toHaveBeenCalledWith('Failed to deactivate user'),
    )
  })

  it('disables action button while operation is in progress', async () => {
    let resolveDeactivate!: () => void
    mockAdminApi.deactivateUser.mockReturnValueOnce(
      new Promise<{ data: { message: string; user: AdminUser } }>((res) => {
        resolveDeactivate = () => res({ data: { message: 'ok', user: { ...activeUser, deactivated: true, deactivated_at: '' } } })
      }),
    )
    const user = userEvent.setup()
    renderPage()

    await waitFor(() => screen.getByText('user@test.com'))
    await user.click(screen.getByRole('button', { name: 'Deactivate' }))

    expect(screen.getByRole('button', { name: 'Deactivate' })).toBeDisabled()

    resolveDeactivate()
    await waitFor(() => expect(screen.getByRole('button', { name: 'Deactivate' })).not.toBeDisabled())
  })

  it('updates user status in table after deactivate', async () => {
    const user = userEvent.setup()
    renderPage()

    await waitFor(() => screen.getByText('user@test.com'))
    await user.click(screen.getByRole('button', { name: 'Deactivate' }))

    await waitFor(() => expect(screen.getByRole('button', { name: 'Activate' })).toBeInTheDocument())
  })
})

